FUNCTION_BLOCK FB_MergeBytes
VAR_INPUT
    byteArray : ARRAY[1..20] OF DINT; (* Byte array to be merged *)
END_VAR

VAR_OUTPUT
    dwordArray : ARRAY[1..10] OF DINT; (* Merged double word array *)
    mergeDwordNum : DINT; (* Actual number of merged double words *)
END_VAR

VAR
    i : DINT; (* Input byte index *)
    j : DINT; (* Byte counter within group (0-3) *)
    k : DINT; (* Output array index *)
    tempDword : DINT; (* Temporary storage for building double word *)
    currentByteValue : DINT; (* Temporary storage for current byte *)
END_VAR

VAR CONSTANT
    BYTE_ARRAY_SIZE : DINT := 20; (* Size of the input byte array *)
    DWORD_ARRAY_SIZE : DINT := 10; (* Size of the output DINT array *)
END_VAR

(* Initialize output count *)
mergeDwordNum := 0;

(* Clear output array *)
FOR k := 1 TO DWORD_ARRAY_SIZE DO
    dwordArray[k] := 0;
END_FOR;

(* Main merging loop *)
i := 1;
WHILE i <= BYTE_ARRAY_SIZE DO
    tempDword := 0;
    j := 0;

    (* Collect up to 4 bytes *)
    WHILE (j < 4) AND ((i + j) <= BYTE_ARRAY_SIZE) DO
        currentByteValue := byteArray[i + j];
        currentByteValue := currentByteValue AND 16#FF; (* Mask to keep only LSB *)
        tempDword := tempDword OR SHL(currentByteValue, 8 * j); (* Shift and combine *)
        j := j + 1;
    END_WHILE;

    (* Check if we have a complete group of 4 bytes *)
    IF j = 4 THEN
        k := mergeDwordNum + 1;

        (* Check if output array has space *)
        IF k <= DWORD_ARRAY_SIZE THEN
            dwordArray[k] := tempDword;
            mergeDwordNum := k;
        ELSE
            EXIT; (* Output array full *)
        END_IF;
    ELSE
        EXIT; (* Incomplete byte group *)
    END_IF;

    i := i + 4; (* Move to next group *)
END_WHILE;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FB_LinearizeValue
VAR_INPUT 
    InputValue : REAL; // Floating point input, raw measurement value
END_VAR

VAR_OUTPUT 
    LinearizedValue : REAL; // Converted linear value
    Error : BOOL; // Error status indicator
    Status : WORD; // Status code
END_VAR

VAR
    // Internal constants for the piecewise linear segments
    RANGE1_IN_MIN : REAL := 1200.0;
    RANGE1_IN_MAX : REAL := 3600.0;
    RANGE1_OUT_MIN : REAL := 150.0;
    RANGE1_OUT_MAX : REAL := 240.0;

    RANGE2_IN_MIN : REAL := 3600.0;
    RANGE2_IN_MAX : REAL := 4800.0;
    RANGE2_OUT_MIN : REAL := 240.0;
    RANGE2_OUT_MAX : REAL := 560.0;

    RANGE3_IN_MIN : REAL := 4800.0;
    RANGE3_IN_MAX : REAL := 7000.0;
    RANGE3_OUT_MIN : REAL := 560.0;
    RANGE3_OUT_MAX : REAL := 720.0;

    // Status codes
    STATUS_SUCCESS : WORD := 16#0000;
    STATUS_OUT_OF_RANGE : WORD := 16#8001;
END_VAR

// Main execution logic
IF InputValue < RANGE1_IN_MIN THEN
    // Below minimum range
    LinearizedValue := RANGE1_OUT_MIN;
    Error := TRUE;
    Status := STATUS_OUT_OF_RANGE;
ELSIF InputValue >= RANGE1_IN_MIN AND InputValue <= RANGE1_IN_MAX THEN
    // Range 1: 1200 to 3600
    LinearizedValue := RANGE1_OUT_MIN + (InputValue - RANGE1_IN_MIN) * 
                      (RANGE1_OUT_MAX - RANGE1_OUT_MIN) / 
                      (RANGE1_IN_MAX - RANGE1_IN_MIN);
    Error := FALSE;
    Status := STATUS_SUCCESS;
ELSIF InputValue > RANGE1_IN_MAX AND InputValue <= RANGE2_IN_MAX THEN
    // Range 2: 3600 to 4800
    LinearizedValue := RANGE2_OUT_MIN + (InputValue - RANGE2_IN_MIN) * 
                      (RANGE2_OUT_MAX - RANGE2_OUT_MIN) / 
                      (RANGE2_IN_MAX - RANGE2_IN_MIN);
    Error := FALSE;
    Status := STATUS_SUCCESS;
ELSIF InputValue > RANGE2_IN_MAX AND InputValue <= RANGE3_IN_MAX THEN
    // Range 3: 4800 to 7000
    LinearizedValue := RANGE3_OUT_MIN + (InputValue - RANGE3_IN_MIN) * 
                      (RANGE3_OUT_MAX - RANGE3_OUT_MIN) / 
                      (RANGE3_IN_MAX - RANGE3_IN_MIN);
    Error := FALSE;
    Status := STATUS_SUCCESS;
ELSE
    // Above maximum range
    LinearizedValue := RANGE3_OUT_MAX;
    Error := TRUE;
    Status := STATUS_OUT_OF_RANGE;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_WarehouseManagement
VAR_INPUT 
    requestIn : BOOL := FALSE;
    requestOut : BOOL := FALSE;
END_VAR

VAR_OUTPUT 
    productNum : INT := 0;
    libFreeNum : INT := 9;
    error : BOOL := FALSE;
    status : WORD := 16#0000;
END_VAR

VAR_IN_OUT 
    library : ARRAY[1..9] OF BOOL;
END_VAR

VAR 
    i : INT;
    found : BOOL;
    initDone : BOOL := FALSE;
    errFull : WORD := 16#8001;
    errEmpty : WORD := 16#8002;
END_VAR

// Initialize library array on first execution
IF NOT initDone THEN
    i := 1;
    WHILE i <= 9 DO
        library[i] := FALSE;
        i := i + 1;
    END_WHILE;
    initDone := TRUE;
END_IF;

// Reset error status at start of each cycle
error := FALSE;
status := 16#0000;

// Handle storage request
IF requestIn THEN
    // Check if storage is full
    IF productNum >= 9 THEN
        error := TRUE;
        status := errFull;
    ELSE
        // Search for free position from highest to lowest index (9 to 1)
        found := FALSE;
        i := 9;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;
                productNum := productNum + 1;
                libFreeNum := libFreeNum - 1;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        // If no free position found despite productNum < 9, set error
        IF NOT found THEN
            error := TRUE;
            status := errFull;
        END_IF;
    END_IF;
END_IF;

// Handle retrieval request
IF requestOut THEN
    // Check if storage is empty
    IF productNum <= 0 THEN
        error := TRUE;
        status := errEmpty;
    ELSE
        // Search for occupied position from lowest to highest index (1 to 9)
        found := FALSE;
        i := 1;
        WHILE i <= 9 AND NOT found DO
            IF library[i] THEN
                library[i] := FALSE;
                productNum := productNum - 1;
                libFreeNum := libFreeNum + 1;
                found := TRUE;
            END_IF;
            i := i + 1;
        END_WHILE;

        // If no occupied position found despite productNum > 0, set error
        IF NOT found THEN
            error := TRUE;
            status := errEmpty;
        END_IF;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

