    GrinderFinishedFlag : BOOL := FALSE;
    CoffeeReadyFlag : BOOL := FALSE;
    ProcessActive : BOOL := FALSE;
END_VAR

(* State Definitions:
   0: Idle
   1: Water Heating
   2: Grinder Running
   3: Brewing
*)

