        END_IF;

    5: (* HIGH_INTENSITY *)
        PanelAngle := NoonAngle;
        State := 1;

    ELSE
        State := 0;
END_CASE;

(* Apply boundary limits to ensure angle stays within 0-90 degrees *)
IF PanelAngle < 0.0 THEN
    PanelAngle := 0.0;
